1	{
2	  "$schema": "https://json-schema.org/draft/2020-12/schema",
3	  "$id": "https://context-profiler/schemas/review-items.schema.json",
4	  "title": "ReviewItemsArtifact",
5	  "description": "Output contract between the profiler pipeline and the UI. The UI consumes this file and the source CLAUDE.md only.",
6	  "type": "object",
7	  "required": ["version", "source", "summary", "items"],
8	  "additionalProperties": false,
9	  "properties": {
10	    "version": {
11	      "type": "integer",
12	      "const": 1
13	    },
14	    "source": {
15	      "type": "object",
16	      "required": ["repoName", "contextPath", "contextHash", "generatedAt"],
17	      "additionalProperties": false,
18	      "properties": {
19	        "repoName": { "type": "string", "minLength": 1 },
20	        "contextPath": { "type": "string", "minLength": 1 },
21	        "contextHash": {
22	          "type": "string",
23	          "pattern": "^sha256:[0-9a-f]{64}$"
24	        },
25	        "generatedAt": { "type": "string", "format": "date-time" }
26	      }
27	    },
28	    "summary": {
29	      "type": "object",
30	      "required": [
31	        "totalInstructions",
32	        "totalRuns",
33	        "verdictCounts",
34	        "statusCounts",
35	        "flagCounts",
36	        "estimatedTokenChange"
37	      ],
38	      "additionalProperties": false,
39	      "properties": {
40	        "totalInstructions": { "type": "integer", "minimum": 0 },
41	        "totalRuns": { "type": "integer", "minimum": 0 },
42	        "verdictCounts": {
43	          "type": "object",
44	          "required": ["keep", "update", "remove", "add_test"],
45	          "additionalProperties": false,
46	          "properties": {
47	            "keep": { "type": "integer", "minimum": 0 },
48	            "update": { "type": "integer", "minimum": 0 },
49	            "remove": { "type": "integer", "minimum": 0 },
50	            "add_test": { "type": "integer", "minimum": 0 }
51	          }
52	        },
53	        "statusCounts": {
54	          "type": "object",
55	          "required": ["supported", "unobserved"],
56	          "additionalProperties": false,
57	          "properties": {
58	            "supported": { "type": "integer", "minimum": 0 },
59	            "unobserved": { "type": "integer", "minimum": 0 }
60	          }
61	        },
62	        "flagCounts": {
63	          "type": "object",
64	          "required": ["conflicting", "stale"],
65	          "additionalProperties": false,
66	          "properties": {
67	            "conflicting": { "type": "integer", "minimum": 0 },
68	            "stale": { "type": "integer", "minimum": 0 }
69	          }
70	        },
71	        "estimatedTokenChange": { "type": "integer" }
72	      }
73	    },
74	    "items": {
75	      "type": "array",
76	      "items": { "$ref": "#/$defs/ReviewItem" }
77	    }
78	  },
79	  "$defs": {
80	    "ReviewItem": {
81	      "type": "object",
82	      "required": [
83	        "id",
84	        "verdict",
85	        "status",
86	        "flags",
87	        "title",
88	        "snippet",
89	        "sourceFile",
90	        "startOffset",
91	        "endOffset",
92	        "tokenCount",
93	        "tokenDelta",
94	        "metrics",
95	        "reason",
96	        "evidence"
97	      ],
98	      "additionalProperties": false,
99	      "properties": {
100	        "id": {
101	          "type": "string",
102	          "pattern": "^instr-[0-9a-f]{8}$"
103	        },
104	        "verdict": {
105	          "type": "string",
106	          "enum": ["keep", "update", "remove", "add_test"]
107	        },
108	        "status": {
109	          "type": "string",
110	          "enum": ["supported", "unobserved"]
111	        },
112	        "flags": {
113	          "type": "array",
114	          "uniqueItems": true,
115	          "items": {
116	            "type": "string",
117	            "enum": ["conflicting", "stale"]
118	          }
119	        },
120	        "title": { "type": "string", "minLength": 1, "maxLength": 80 },
121	        "snippet": { "type": "string", "minLength": 1 },
122	        "sourceFile": { "type": "string", "minLength": 1 },
123	        "startOffset": { "type": "integer", "minimum": 0 },
124	        "endOffset": { "type": "integer", "minimum": 0 },
125	        "tokenCount": { "type": "integer", "minimum": 0 },
126	        "tokenDelta": { "type": "integer" },
127	        "metrics": {
128	          "type": "object",
129	          "required": ["sessionsObserved", "totalSessions", "traceEvents"],
130	          "additionalProperties": false,
131	          "properties": {
132	            "sessionsObserved": { "type": "integer", "minimum": 0 },
133	            "totalSessions": { "type": "integer", "minimum": 0 },
134	            "traceEvents": { "type": "integer", "minimum": 0 }
135	          }
136	        },
137	        "reason": { "type": "string", "minLength": 1 },
138	        "evidence": {
139	          "type": "array",
140	          "items": { "$ref": "#/$defs/Evidence" }
141	        },
142	        "proposedChange": { "$ref": "#/$defs/ProposedChange" }
143	      }
144	    },
145	    "Evidence": {
146	      "type": "object",
147	      "required": ["id", "kind", "context_variant", "label", "source", "excerpt", "explanation"],
148	      "additionalProperties": false,
149	      "properties": {
150	        "id": { "type": "string", "pattern": "^ev-[0-9a-f]{6}$" },
151	        "kind": {
152	          "type": "string",
153	          "enum": ["trace", "absence", "conflict", "ablation"]
154	        },
155	        "context_variant": {
156	          "type": "string",
157	          "pattern": "^(full|ablate:instr-[0-9a-f]{8})$"
158	        },
159	        "label": { "type": "string", "minLength": 1 },
160	        "source": { "type": "string", "minLength": 1 },
161	        "excerpt": { "type": "string" },
162	        "explanation": { "type": "string", "minLength": 1 }
163	      }
164	    },
165	    "ProposedChange": {
166	      "type": "object",
167	      "required": ["kind", "rationale"],
168	      "additionalProperties": false,
169	      "properties": {
170	        "kind": {
171	          "type": "string",
172	          "enum": ["update", "remove", "add_test"]
173	        },
174	        "rationale": { "type": "string", "minLength": 1 },
175	        "replacement": { "type": "string" },
176	        "suggestedTest": { "type": "string" }
177	      }
178	    }
179	  }
180	}
181

1	{
2	  "$schema": "https://json-schema.org/draft/2020-12/schema",
3	  "$id": "https://context-profiler/schemas/instructions.schema.json",
4	  "title": "InstructionsArtifact",
5	  "description": "Output of Stage 3 (extract-instructions). One instruction per source paragraph (or merged tightly-coupled bullets). Snippets and offsets must round-trip through source.slice(start, end).",
6	  "type": "object",
7	  "required": ["version", "source", "extraction", "instructions"],
8	  "additionalProperties": false,
9	  "properties": {
10	    "version": { "type": "integer", "const": 1 },
11	    "source": {
12	      "type": "object",
13	      "required": ["repoName", "contextPath", "contextHash"],
14	      "additionalProperties": false,
15	      "properties": {
16	        "repoName": { "type": "string", "minLength": 1 },
17	        "contextPath": { "type": "string", "minLength": 1 },
18	        "contextHash": { "type": "string", "pattern": "^sha256:[0-9a-f]{64}$" }
19	      }
20	    },
21	    "extraction": {
22	      "type": "object",
23	      "required": ["model", "promptVersion", "anchorFallbacks", "generatedAt"],
24	      "additionalProperties": false,
25	      "properties": {
26	        "model": { "type": "string", "minLength": 1 },
27	        "promptVersion": { "type": "integer", "minimum": 1 },
28	        "anchorFallbacks": { "type": "integer", "minimum": 0 },
29	        "generatedAt": { "type": "string", "format": "date-time" }
30	      }
31	    },
32	    "instructions": {
33	      "type": "array",
34	      "items": {
35	        "type": "object",
36	        "required": ["id", "title", "snippet", "sourceFile", "startOffset", "endOffset"],
37	        "additionalProperties": false,
38	        "properties": {
39	          "id": { "type": "string", "pattern": "^instr-[0-9a-f]{8}$" },
40	          "title": { "type": "string", "minLength": 1, "maxLength": 80 },
41	          "snippet": { "type": "string", "minLength": 1 },
42	          "sourceFile": { "type": "string", "minLength": 1 },
43	          "startOffset": { "type": "integer", "minimum": 0 },
44	          "endOffset": { "type": "integer", "minimum": 0 }
45	        }
46	      }
47	    }
48	  }
49	}
